changeSet.sql:
CREATE TABLE risk_types
(
	id serial,
	name character varying (127) NOT NULL,
	description text DEFAULT NULL,
	category_domain_id integer NOT NULL,
	created_at timestamp without time zone NOT NULL DEFAULT now(),
	updated_at timestamp without time zone NOT NULL DEFAULT now(),
	CONSTRAINT pk_risk_types PRIMARY KEY (id)
	, CONSTRAINT fk_risk_types_to_category_domains FOREIGN KEY (category_domain_id) REFERENCES category_domains (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_risk_types_name ON risk_types (name);
CREATE INDEX i_risk_types_category_domain_id ON risk_types (category_domain_id);
